// The companion logo, inlined as a base64 data URI.
//
// Inlined deliberately: when served as a /public file behind the self-hosted
// ngrok + Caddy + Next standalone stack, the separate image request did not
// reach the browser even though the server returned 200. Embedding the bytes
// in the page removes that request entirely, so the logo always renders.
// Source: public/companion-logo.png, downscaled to 256x256 (only shown small).
export const LOGO_SRC =
  "data:image/png;base64,";
